func Test_FormatDocxStandalone(t *testing.T) {
	// Standalone DOCX extraction using extract
	inputMockBaseURL := os.Getenv("MOCK_SERVER_FORMAT_DOCX_STANDALONE")
	if inputMockBaseURL == "" {
		inputMockBaseURL = os.Getenv("MOCK_SERVER_URL") + "/fixtures/format_docx_standalone"
	}
	inputJSON := strings.ReplaceAll(`{"kind":"uri","uri":"$mock_url/docx/fake.docx","mime_type":"application/vnd.openxmlformats-officedocument.wordprocessingml.document","filename":"fake.docx"}`, "$mock_url", inputMockBaseURL)
	var input xberg.ExtractInput
	if err := json.Unmarshal([]byte(inputJSON), &input); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := xberg.Extract(input, xberg.ExtractionConfig{})
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if len(result.Results) > 0 {
		assert.GreaterOrEqual(t, len(result.Results[0].Content), 20, "expected length >= 20")
	}
}

